const withTimeline = (record: QARecord): QARecord => ({
  ...record,
  timeline: record.timeline.length ? record.timeline : [
    { label: "Assessment completed", date: record.assessmentCompleted, detail: `${record.bcba} completed assessment.` },
    { label: "Treatment plan due", date: record.planDue, detail: "14-day treatment plan SLA." },
    ...(record.planReceived ? [{ label: "Treatment plan submitted", date: record.planReceived, detail: record.treatmentPlanStatus }] : []),
    ...(record.qaStarted ? [{ label: "QA started", date: record.qaStarted, detail: `${record.qaOwner} started review.` }] : []),
    ...(record.issueType !== "None" ? [{ label: "Issues found", date: "2026-04-26", detail: record.issueType }] : []),
    ...(record.qaCompleted ? [{ label: "QA approved", date: record.qaCompleted, detail: "Ready for authorization handoff." }] : []),
  ],
});

const recordsSeed = seedRecords.map(withTimeline);
const ALL = "All";
const statusTone = (status: string): Health => status.includes("Ready") || status.includes("Submitted") ? "success" : status.includes("Issue") || status.includes("Overdue") || status.includes("Blocked") || status.includes("Missing") ? "destructive" : status.includes("Correction") || status.includes("Review") ? "warning" : "muted";
const kpiMatches = (key: KpiKey | null, r: QARecord) => !key ||
  (key === "awaiting" && r.qaStatus === "Awaiting Review") ||
  (key === "inReview" && r.qaStatus === "In Review") ||
  (key === "issues" && ["Issues Found", "Corrections Needed"].includes(r.qaStatus)) ||
  (key === "ready" && r.qaStatus === "Ready for Submission") ||
  (key === "overdue" && (r.qaStatus === "Overdue" || r.alerts.some((a) => a.toLowerCase().includes("overdue")))) ||
  (key === "notes" && r.notesFlagged > 0) ||
  (key === "newRbt" && r.newRbt) ||
  (key === "turnaround" && r.daysInQA > 3);

const kpiAlertCopy = (key: KpiKey, records: QARecord[]) => {
  const blocked = records.filter((r) => r.authReadiness === "Blocked").length;
  const openTasks = records.reduce((sum, r) => sum + r.tasks.filter((t) => t.status === "Open").length, 0);
  const oldest = records.reduce<QARecord | null>((max, r) => !max || r.daysInQA > max.daysInQA ? r : max, null);
  const map: Record<KpiKey, { title: string; detail: string; tone: Health }> = {
    awaiting: { title: `${records.length} plans need intake triage`, detail: "Start review, confirm owner assignment, and identify missing treatment plan artifacts before auth prep stalls.", tone: records.length ? "warning" : "success" },
    inReview: { title: `${records.length} reviews actively moving`, detail: `${oldest ? `${oldest.client} is oldest at ${oldest.daysInQA} days. ` : ""}Escalate anything crossing the 3-day QA target.`, tone: records.some((r) => r.daysInQA > 3) ? "warning" : "info" },
    issues: { title: `${blocked} records blocking authorization`, detail: `${openTasks} open fix tasks are tied to QA issues. Prioritize payer-specific and missing-document blockers first.`, tone: blocked ? "destructive" : "warning" },
    ready: { title: `${records.length} packets can move to auth`, detail: "Marking ready keeps QA approved, sets linked treatment auth to Awaiting Submission, and moves the client toward Pending Treatment Auth.", tone: "success" },
    overdue: { title: `${records.length} treatment plan SLA exceptions`, detail: `${oldest ? `${oldest.client} is the highest-risk item. ` : ""}Alert logic includes overdue QA status and treatment-plan overdue flags.`, tone: records.length ? "destructive" : "success" },
    notes: { title: `${records.reduce((sum, r) => sum + r.notesFlagged, 0)} flagged notes in scope`, detail: "Alert logic highlights NoteGuard flags, repeated note errors, and Amerigroup-specific documentation corrections.", tone: "warning" },
    newRbt: { title: `${records.length} new RBT monitoring cases`, detail: "Includes first-week check-ins, early note quality, payer flags, and coaching tasks linked to the client QA record.", tone: "info" },
    turnaround: { title: `${records.length} reviews over target`, detail: "Shows records above the 3-day QA turnaround goal so owners can rebalance workload and escalate blockers.", tone: records.length ? "warning" : "success" },
  };
  return map[key];
};

export default function QADashboard() {
  const [records, setRecords] = useState(recordsSeed);
  const [selected, setSelected] = useState<QARecord | null>(recordsSeed[0]);
  const [kpiFilter, setKpiFilter] = useState<KpiKey | null>(null);
  const [kpiTable, setKpiTable] = useState<KpiKey | null>(null);
  const [filters, setFilters] = useState({ range: "30 days", state: ALL, owner: ALL, bcba: ALL, rbt: ALL, payor: ALL, status: ALL, stage: ALL, search: "" });

  const options = useMemo(() => ({
    states: Array.from(new Set(records.map((r) => r.state))), owners: Array.from(new Set(records.map((r) => r.qaOwner))), bcbas: Array.from(new Set(records.map((r) => r.bcba))), rbts: Array.from(new Set(records.map((r) => r.rbt))), payors: Array.from(new Set(records.map((r) => r.payor))), statuses: Array.from(new Set(records.map((r) => r.qaStatus))), stages: Array.from(new Set(records.map((r) => r.stage))),
  }), [records]);

  const filtered = useMemo(() => records.filter((r) => {
    const q = filters.search.toLowerCase().trim();
    return kpiMatches(kpiFilter, r) &&
      (filters.state === ALL || r.state === filters.state) &&
      (filters.owner === ALL || r.qaOwner === filters.owner) &&
      (filters.bcba === ALL || r.bcba === filters.bcba) &&
      (filters.rbt === ALL || r.rbt === filters.rbt) &&
      (filters.payor === ALL || r.payor === filters.payor) &&
      (filters.status === ALL || r.qaStatus === filters.status) &&
      (filters.stage === ALL || r.stage === filters.stage) &&
      (!q || [r.client, r.bcba, r.rbt, r.qaOwner, r.payor, r.issueType, r.nextAction].join(" ").toLowerCase().includes(q));
  }), [filters, kpiFilter, records]);

  const metrics = useMemo(() => {
    const avg = (nums: number[]) => nums.length ? Math.round((nums.reduce((a, b) => a + b, 0) / nums.length) * 10) / 10 : 0;
    return {
      awaiting: records.filter((r) => r.qaStatus === "Awaiting Review").length,
      inReview: records.filter((r) => r.qaStatus === "In Review").length,
      issues: records.filter((r) => ["Issues Found", "Corrections Needed"].includes(r.qaStatus)).length,
      ready: records.filter((r) => r.qaStatus === "Ready for Submission").length,
      overdue: records.filter((r) => r.qaStatus === "Overdue" || r.alerts.some((a) => a.includes("overdue"))).length,
      notes: records.reduce((sum, r) => sum + r.notesFlagged, 0),
      newRbt: records.filter((r) => r.newRbt).length,
      avgTurnaround: avg(records.filter((r) => r.qaStarted).map((r) => r.daysInQA || 1)),
      avgAssessmentToPlan: avg(records.filter((r) => r.planReceived).map((r) => Math.max(1, r.daysSinceAssessment - 3))),
      onTimePct: Math.round((records.filter((r) => r.planReceived && !r.alerts.includes("Treatment plan overdue")).length / Math.max(1, records.filter((r) => r.planReceived).length)) * 100),
    };
  }, [records]);

  const updateRecord = (id: string, patch: Partial<QARecord>, message: string) => {
    setRecords((current) => current.map((r) => r.id === id ? { ...r, ...patch, timeline: [...r.timeline, { label: message, date: "Now", detail: "Updated from QA Dashboard quick action." }] } : r));
    setSelected((current) => current?.id === id ? { ...current, ...patch, timeline: [...current.timeline, { label: message, date: "Now", detail: "Updated from QA Dashboard quick action." }] } : current);
    toast.success(message);
  };

  const markReady = (r: QARecord) => updateRecord(r.id, { qaStatus: "Ready for Submission", authStatus: "Awaiting Submission", authReadiness: "Ready", stage: "Pending Treatment Auth", nextAction: "Submit treatment authorization", alerts: r.alerts.filter((a) => !a.includes("blocking") && !a.includes("Missing")), checklist: { ...r.checklist, ready: true } }, "Marked ready for submission");

  const createFixTask = (r: QARecord) => {
    const owner = r.issueType.toLowerCase().includes("note") || r.newRbt ? r.rbt : r.bcba;
    const due = new Intl.DateTimeFormat("en-US", { month: "short", day: "numeric" }).format(new Date(Date.now() + (r.qaStatus === "Overdue" || r.authReadiness === "Blocked" ? 24 : 48) * 60 * 60 * 1000));
    const task = { title: `QA fix: ${r.issueType === "None" ? "Documentation follow-up" : r.issueType}`, owner, due, status: "Open" as const, linkedRecordId: r.id, createdFrom: "QA Dashboard" };
    const timelineEvent = { label: "Fix task created", date: "Now", detail: `${task.title} assigned to ${owner}, due ${due}. Linked to ${r.id}.` };
    const patch = { tasks: [...r.tasks, task], nextAction: `Complete fix task with ${owner}`, alerts: Array.from(new Set([...r.alerts, "Fix task open"])) };
    setRecords((current) => current.map((record) => record.id === r.id ? { ...record, ...patch, timeline: [...record.timeline, timelineEvent] } : record));
    setSelected((current) => current?.id === r.id ? { ...current, ...patch, timeline: [...current.timeline, timelineEvent] } : current);
    toast.success(`Fix task assigned to ${owner} · due ${due}`);
  };

  const kpis: { key: KpiKey; label: string; value: string | number; sub: string; icon: typeof ClipboardCheck; tone: Health }[] = [
    { key: "awaiting", label: "Awaiting QA Review", value: metrics.awaiting, sub: "New plans waiting", icon: ClipboardCheck, tone: "warning" as Health },
    { key: "inReview", label: "In QA Review", value: metrics.inReview, sub: "Active reviews", icon: Eye, tone: "info" as Health },
    { key: "issues", label: "Issues Found", value: metrics.issues, sub: "Needs BCBA/RBT fixes", icon: ShieldAlert, tone: "destructive" as Health },
    { key: "ready", label: "Ready for Submission", value: metrics.ready, sub: "Can move to auth", icon: ShieldCheck, tone: "success" as Health },
    { key: "overdue", label: "Overdue Treatment Plans", value: metrics.overdue, sub: "Past 14-day SLA", icon: AlertTriangle, tone: "destructive" as Health },
    { key: "notes", label: "Notes Flagged", value: metrics.notes, sub: "NoteGuard + payer flags", icon: Flag, tone: "warning" as Health },
    { key: "newRbt", label: "New RBTs Monitored", value: metrics.newRbt, sub: "First 1–2 week support", icon: UserCheck, tone: "info" as Health },
    { key: "turnaround", label: "Avg QA Turnaround", value: `${metrics.avgTurnaround}d`, sub: "Target under 3 days", icon: Timer, tone: metrics.avgTurnaround > 3 ? "warning" : "success" },
  ];

  const kpiTableRows = useMemo(() => kpiTable ? records.filter((r) => kpiMatches(kpiTable, r)) : [], [kpiTable, records]);
  const activeKpi = kpis.find((kpi) => kpi.key === kpiTable) ?? null;

  return <div className="space-y-6 animate-fade-in">
    <header className="space-y-4"><div className="flex flex-col gap-3 xl:flex-row xl:items-end xl:justify-between"><div><h1 className="text-3xl font-semibold tracking-tight text-foreground">QA Dashboard</h1><p className="mt-1 text-sm text-muted-foreground">Treatment plan review, documentation quality, note compliance, and auth readiness.</p></div><div className="flex flex-wrap gap-2"><Button variant="outline" onClick={() => toast.success("QA dashboard refreshed")}><RefreshCw className="mr-2 h-4 w-4" />Refresh</Button><Button onClick={() => toast.success(`Exported ${filtered.length} QA rows`)}><Download className="mr-2 h-4 w-4" />Export</Button></div></div>
      <div className="sticky top-0 z-10 rounded-2xl border border-border/60 bg-card/95 p-3 shadow-sm backdrop-blur"><div className="grid gap-2 md:grid-cols-4 xl:grid-cols-8"><Select value={filters.range} onValueChange={(range) => setFilters({ ...filters, range })}><SelectTrigger><SelectValue /></SelectTrigger><SelectContent>{["7 days", "30 days", "Quarter", "All time"].map((item) => <SelectItem key={item} value={item}>{item}</SelectItem>)}</SelectContent></Select><FilterSelect value={filters.state} values={options.states} onChange={(state) => setFilters({ ...filters, state })} placeholder="State" /><FilterSelect value={filters.owner} values={options.owners} onChange={(owner) => setFilters({ ...filters, owner })} placeholder="QA owner" /><FilterSelect value={filters.bcba} values={options.bcbas} onChange={(bcba) => setFilters({ ...filters, bcba })} placeholder="BCBA" /><FilterSelect value={filters.rbt} values={options.rbts} onChange={(rbt) => setFilters({ ...filters, rbt })} placeholder="RBT" /><FilterSelect value={filters.payor} values={options.payors} onChange={(payor) => setFilters({ ...filters, payor })} placeholder="Payor" /><FilterSelect value={filters.status} values={options.statuses} onChange={(status) => setFilters({ ...filters, status })} placeholder="QA status" /><FilterSelect value={filters.stage} values={options.stages} onChange={(stage) => setFilters({ ...filters, stage })} placeholder="Client stage" /></div><div className="relative mt-2"><Search className="absolute z-10 left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground" /><Input value={filters.search} onChange={(event) => setFilters({ ...filters, search: event.target.value })} placeholder="Search clients, owners, issue types, payors..." className="pl-9" /></div></div></header>

    <section className="grid gap-3 md:grid-cols-4 xl:grid-cols-8">{kpis.map(({ key, label, value, sub, icon: Icon, tone }) => <button key={key} onClick={() => { setKpiFilter(key); setKpiTable(key); }} className={cn("rounded-2xl border bg-card p-4 text-left shadow-sm transition-all hover:-translate-y-0.5 hover:shadow-md", kpiFilter === key ? "border-primary/50 ring-2 ring-primary/15" : "border-border/60")}><div className="mb-3 flex items-center justify-between"><Icon className={cn("h-4 w-4", tone === "destructive" ? "text-destructive" : tone === "warning" ? "text-warning" : tone === "success" ? "text-success" : "text-primary")} /><span className={cn("h-2 w-2 rounded-full", tone === "destructive" ? "bg-destructive" : tone === "warning" ? "bg-warning" : tone === "success" ? "bg-success" : "bg-primary")} /></div><p className="text-2xl font-semibold text-foreground">{value}</p><p className="mt-1 line-clamp-2 text-xs font-medium text-foreground">{label}</p><p className="mt-1 text-[11px] text-muted-foreground">{sub}</p></button>)}</section>
    {activeKpi && <KpiRecordTable kpi={activeKpi} rows={kpiTableRows} onClose={() => { setKpiTable(null); setKpiFilter(null); }} onSelect={setSelected} onReady={markReady} onCreateFixTask={createFixTask} updateRecord={updateRecord} />}

    <section className="grid gap-5 xl:grid-cols-[1.2fr_0.8fr]"><ActionQueue records={filtered} onSelect={setSelected} onReady={markReady} onCreateFixTask={createFixTask} updateRecord={updateRecord} /><ReadinessSnapshot records={records} /></section>
    <FlowBoard records={records} />
    <section className="grid gap-5 xl:grid-cols-2"><TimelinePanel records={records} metrics={metrics} /><NoteCompliancePanel records={records} /></section>
    <section className="grid gap-5 xl:grid-cols-2"><SupportPanel records={records} /><OwnerPerformance records={records} /></section>
    <Worklist records={filtered} onSelect={setSelected} onReady={markReady} onCreateFixTask={createFixTask} updateRecord={updateRecord} />
    <DetailPanel record={selected} onOpenChange={(open) => !open && setSelected(null)} onReady={markReady} onCreateFixTask={createFixTask} updateRecord={updateRecord} />
  </div>;
}

function KpiRecordTable({ kpi, rows, onClose, onSelect, onReady, onCreateFixTask, updateRecord }: { kpi: { key: KpiKey; label: string; sub: string; tone: Health }; rows: QARecord[]; onClose: () => void; onSelect: (r: QARecord) => void; onReady: (r: QARecord) => void; onCreateFixTask: (r: QARecord) => void; updateRecord: (id: string, patch: Partial<QARecord>, message: string) => void }) {
  const alert = kpiAlertCopy(kpi.key, rows);
  return <Panel title={`${kpi.label} Records`} icon={Filter} action={<div className="flex items-center gap-2"><span className="text-xs text-muted-foreground">{rows.length} matched</span><Button size="sm" variant="outline" onClick={onClose}>Clear KPI</Button></div>}><div className={cn("mb-4 rounded-xl border p-4", alert.tone === "destructive" ? "border-destructive/30 bg-destructive/5" : alert.tone === "warning" ? "border-warning/30 bg-warning/5" : alert.tone === "success" ? "border-success/30 bg-success/5" : "border-primary/30 bg-primary/5")}><div className="flex items-start gap-3"><AlertTriangle className={cn("mt-0.5 h-5 w-5", alert.tone === "destructive" ? "text-destructive" : alert.tone === "warning" ? "text-warning" : alert.tone === "success" ? "text-success" : "text-primary")} /><div><h3 className="font-semibold text-foreground">{alert.title}</h3><p className="mt-1 text-sm text-muted-foreground">{alert.detail}</p></div></div></div><div className="overflow-x-auto"><table className="w-full text-sm"><thead className="bg-muted/40 text-[11px] uppercase tracking-wider text-muted-foreground"><tr>{["Client", "QA Status", "Alert Logic", "Owner", "Days", "Notes", "Auth", "Next Action", "Actions"].map((h) => <th key={h} className="whitespace-nowrap px-3 py-2 text-left font-medium">{h}</th>)}</tr></thead><tbody>{rows.map((r) => <tr key={`kpi-${r.id}`} className="border-t border-border/50"><td className="px-3 py-3"><button onClick={() => onSelect(r)} className="font-medium text-foreground hover:text-primary">{r.client}</button><p className="text-xs text-muted-foreground">{r.state} · {r.payor} · {r.bcba}</p></td><td className="px-3 py-3"><StatusBadge status={r.qaStatus} variant={statusTone(r.qaStatus)} /></td><td className="px-3 py-3 min-w-60"><div className="flex flex-wrap gap-1">{[...r.alerts, ...(r.notesFlagged > 0 ? [`${r.notesFlagged} notes flagged`] : []), ...(r.newRbt ? ["New RBT monitoring"] : []), ...(r.daysInQA > 3 ? ["QA turnaround over target"] : [])].slice(0, 4).map((a) => <StatusBadge key={a} status={a} variant={a.toLowerCase().includes("overdue") || a.toLowerCase().includes("blocking") ? "destructive" : "warning"} />)}</div></td><td className="px-3 py-3 text-xs text-muted-foreground">{r.qaOwner}</td><td className="px-3 py-3">{r.daysInQA} QA<br /><span className="text-xs text-muted-foreground">{r.daysSinceAssessment} since assessment</span></td><td className="px-3 py-3">{r.notesFlagged}/{r.notesReviewed}</td><td className="px-3 py-3"><StatusBadge status={r.authReadiness} variant={statusTone(r.authReadiness)} /></td><td className="px-3 py-3 min-w-52">{r.nextAction}</td><td className="px-3 py-3"><div className="flex flex-wrap gap-2"><Button size="sm" variant="outline" onClick={() => onSelect(r)}>Open</Button><Button size="sm" variant="outline" onClick={() => updateRecord(r.id, { qaStatus: "In Review", qaStarted: "Now", daysInQA: Math.max(1, r.daysInQA) }, "Review started")}>Start</Button><Button size="sm" variant="outline" onClick={() => onCreateFixTask(r)}>Fix Task</Button><Button size="sm" onClick={() => onReady(r)}>Ready</Button></div></td></tr>)}</tbody></table></div></Panel>;
}

function FilterSelect({ value, values, onChange, placeholder }: { value: string; values: string[]; onChange: (value: string) => void; placeholder: string }) { return <Select value={value} onValueChange={onChange}><SelectTrigger><SelectValue placeholder={placeholder} /></SelectTrigger><SelectContent><SelectItem value={ALL}>{placeholder}: All</SelectItem>{values.map((item) => <SelectItem key={item} value={item}>{item}</SelectItem>)}</SelectContent></Select>; }

function Panel({ title, icon: Icon, children, action }: { title: string; icon: typeof ClipboardCheck; children: ReactNode; action?: ReactNode }) { return <section className="rounded-2xl border border-border/60 bg-card shadow-sm"><div className="flex items-center justify-between border-b border-border/60 p-4"><div className="flex items-center gap-2"><Icon className="h-5 w-5 text-primary" /><h2 className="font-semibold text-foreground">{title}</h2></div>{action}</div><div className="p-4">{children}</div></section>; }

function ActionQueue({ records, onSelect, onReady, onCreateFixTask, updateRecord }: { records: QARecord[]; onSelect: (r: QARecord) => void; onReady: (r: QARecord) => void; onCreateFixTask: (r: QARecord) => void; updateRecord: (id: string, patch: Partial<QARecord>, message: string) => void }) {
  const groups = [{ title: "Urgent Now", rows: records.filter((r) => r.alerts.length || r.qaStatus === "Overdue").slice(0, 6) }, { title: "Review Today", rows: records.filter((r) => ["Awaiting Review", "In Review"].includes(r.qaStatus)).slice(0, 5) }, { title: "Compliance Risks", rows: records.filter((r) => r.repeatNoteErrors > 1 || r.newRbt || r.issueType.includes("Missing")).slice(0, 5) }];
  return <Panel title="QA Action Queue" icon={Bell}><div className="space-y-5">{groups.map((group) => <div key={group.title}><div className="mb-2 flex items-center justify-between"><h3 className="text-sm font-semibold text-foreground">{group.title}</h3><span className="text-xs text-muted-foreground">{group.rows.length} items</span></div><div className="space-y-2">{group.rows.map((r) => <div key={`${group.title}-${r.id}`} className="rounded-xl border border-border/60 bg-background p-3"><div className="grid gap-3 xl:grid-cols-[1fr_0.8fr_0.8fr_0.7fr_0.8fr_1fr]"><div><button className="font-medium text-foreground hover:text-primary" onClick={() => onSelect(r)}>{r.client}</button><p className="text-xs text-muted-foreground">{r.state} · {r.payor}</p></div><p className="text-xs text-muted-foreground">BCBA<br /><span className="font-medium text-foreground">{r.bcba}</span></p><p className="text-xs text-muted-foreground">QA Owner<br /><span className="font-medium text-foreground">{r.qaOwner}</span></p><div><StatusBadge status={r.qaStatus} variant={statusTone(r.qaStatus)} /><p className="mt-1 text-xs text-muted-foreground">{r.daysInQA} days</p></div><p className="text-xs text-muted-foreground">Issue<br /><span className="font-medium text-foreground">{r.issueType}</span></p><p className="text-xs text-muted-foreground">Next<br /><span className="font-medium text-foreground">{r.nextAction}</span></p></div><div className="mt-3 flex flex-wrap gap-2"><Button size="sm" variant="outline" onClick={() => onSelect(r)}>Open QA</Button><Button size="sm" variant="outline" onClick={() => updateRecord(r.id, { qaStatus: "In Review", qaStarted: "Now", daysInQA: Math.max(1, r.daysInQA) }, "Review started")}>Start Review</Button><Button size="sm" variant="outline" onClick={() => updateRecord(r.id, { qaStatus: "Issues Found", issueType: r.issueType === "None" ? "Documentation issue" : r.issueType, authReadiness: "Blocked" }, "Issues marked")}>Mark Issues Found</Button><Button size="sm" onClick={() => onReady(r)}>Mark Ready</Button><Button size="sm" variant="outline" onClick={() => onCreateFixTask(r)}>Create Fix Task</Button><Button size="sm" variant="outline" onClick={() => toast.success(`Notified ${r.bcba}`)}>Notify BCBA</Button><Button size="sm" variant="ghost" onClick={() => toast.info(`Opening client ${r.client}`)}>Open Client</Button></div></div>)}</div></div>)}</div></Panel>;
}

function ReadinessSnapshot({ records }: { records: QARecord[] }) { const rows = [["Ready for auth", records.filter((r) => r.authReadiness === "Ready").length, "success"], ["Blocked by issues", records.filter((r) => r.authReadiness === "Blocked").length, "destructive"], ["Overdue treatment plans", records.filter((r) => r.alerts.includes("Treatment plan overdue")).length, "warning"], ["Notes flagged today", records.reduce((s, r) => s + r.notesFlagged, 0), "warning"], ["New RBT check-ins due", records.filter((r) => r.newRbt && r.tasks.some((t) => t.title.includes("RBT") || t.title.includes("check-in"))).length, "info"]] as const; return <Panel title="QA Readiness Snapshot" icon={ShieldCheck}><div className="space-y-3">{rows.map(([label, value, tone]) => <div key={label} className="flex items-center justify-between rounded-xl border border-border/60 bg-background p-4"><span className="text-sm text-muted-foreground">{label}</span><span className={cn("text-2xl font-semibold", tone === "destructive" ? "text-destructive" : tone === "warning" ? "text-warning" : tone === "success" ? "text-success" : "text-primary")}>{value}</span></div>)}</div></Panel>; }

function FlowBoard({ records }: { records: QARecord[] }) { const stages: QAStatus[] = ["Awaiting Review", "In Review", "Issues Found", "Corrections Needed", "Ready for Submission", "Submitted to Auth", "Overdue"]; return <Panel title="QA Flow Board" icon={ListChecks}><div className="grid gap-3 xl:grid-cols-7">{stages.map((stage) => { const rows = records.filter((r) => r.qaStatus === stage); const avg = rows.length ? Math.round(rows.reduce((s, r) => s + r.daysInQA, 0) / rows.length) : 0; const oldest = rows.sort((a, b) => b.daysInQA - a.daysInQA)[0]; const tone = statusTone(stage); return <div key={stage} className="rounded-xl border border-border/60 bg-background p-3"><div className="flex items-center justify-between"><span className={cn("h-2.5 w-2.5 rounded-full", tone === "destructive" ? "bg-destructive" : tone === "warning" ? "bg-warning" : tone === "success" ? "bg-success" : "bg-primary")} /><span className="text-2xl font-semibold text-foreground">{rows.length}</span></div><h3 className="mt-3 text-sm font-semibold text-foreground">{stage}</h3><p className="mt-2 text-xs text-muted-foreground">Oldest: {oldest ? `${oldest.client} · ${oldest.daysInQA}d` : "—"}</p><p className="text-xs text-muted-foreground">Avg days: {avg}</p></div>; })}</div></Panel>; }

function TimelinePanel({ records, metrics }: { records: QARecord[]; metrics: { avgAssessmentToPlan: number; avgTurnaround: number; onTimePct: number; overdue: number } }) { return <Panel title="Assessment to QA Timeline" icon={CalendarDays}><div className="grid gap-3 md:grid-cols-4">{[["Avg Assessment → Plan", `${metrics.avgAssessmentToPlan}d`], ["Avg Plan → QA Complete", `${metrics.avgTurnaround}d`], ["Plans on time", `${metrics.onTimePct}%`], ["Overdue reports", metrics.overdue]].map(([l, v]) => <div key={l} className="rounded-xl border border-border/60 bg-background p-3"><p className="text-xs text-muted-foreground">{l}</p><p className="mt-1 text-xl font-semibold text-foreground">{v}</p></div>)}</div><div className="mt-4 space-y-2">{records.slice(0, 6).map((r) => <div key={r.id} className="grid gap-2 rounded-xl border border-border/60 bg-background p-3 text-xs md:grid-cols-5"><span className="font-medium text-foreground">{r.client}</span><span>Assessment {r.assessmentCompleted}</span><span>Due {r.planDue}</span><span>Received {r.planReceived ?? "—"}</span><span>QA {r.qaCompleted ?? r.qaStarted ?? "Not started"}</span></div>)}</div></Panel>; }

function NoteCompliancePanel({ records }: { records: QARecord[] }) { const total = records.reduce((s, r) => s + r.notesReviewed, 0); const flagged = records.reduce((s, r) => s + r.notesFlagged, 0); const repeat = records.filter((r) => r.repeatNoteErrors > 1).length; const amerigroup = records.filter((r) => r.amerigroupIssue).length; return <Panel title="Note Compliance" icon={FileCheck2}><div className="grid gap-3 md:grid-cols-6">{[["Reviewed", total], ["Flagged", flagged], ["Flag rate", `${Math.round(flagged / Math.max(1, total) * 100)}%`], ["Repeat offenders", repeat], ["Amerigroup", amerigroup], ["NoteGuard", records.reduce((s, r) => s + r.noteGuardIssues, 0)]].map(([l, v]) => <div key={l} className="rounded-xl border border-border/60 bg-background p-3"><p className="text-xs text-muted-foreground">{l}</p><p className="mt-1 text-xl font-semibold text-foreground">{v}</p></div>)}</div><div className="mt-4 grid gap-2 md:grid-cols-2">{records.filter((r) => r.notesFlagged > 0).slice(0, 6).map((r) => <div key={r.id} className="rounded-xl border border-border/60 bg-background p-3"><p className="text-sm font-medium text-foreground">{r.rbt} · {r.client}</p><p className="text-xs text-muted-foreground">{r.bcba} · {r.payor} · {r.state}</p><Progress value={Math.round((r.notesFlagged / Math.max(1, r.notesReviewed)) * 100)} className="mt-2 h-2" /></div>)}</div></Panel>; }

function SupportPanel({ records }: { records: QARecord[] }) { const bcbas = Array.from(new Set(records.map((r) => r.bcba))).slice(0, 4); const newRbt = records.filter((r) => r.newRbt); return <Panel title="BCBA / RBT Support" icon={Stethoscope}><div className="grid gap-4 md:grid-cols-2"><div><h3 className="mb-2 text-sm font-semibold text-foreground">BCBA Performance</h3><div className="space-y-2">{bcbas.map((bcba) => { const rows = records.filter((r) => r.bcba === bcba); const pass = Math.round((rows.filter((r) => r.authReadiness === "Ready").length / rows.length) * 100); return <div key={bcba} className="rounded-xl border border-border/60 bg-background p-3"><p className="font-medium text-foreground">{bcba}</p><p className="text-xs text-muted-foreground">Pending reports {rows.filter((r) => r.authReadiness !== "Ready").length} · Avg report time {Math.round(rows.reduce((s, r) => s + r.daysSinceAssessment, 0) / rows.length)}d</p><p className="text-xs text-muted-foreground">QA pass {pass}% · Corrections {rows.filter((r) => r.issueType !== "None").length}</p></div>; })}</div></div><div><h3 className="mb-2 text-sm font-semibold text-foreground">New RBT Monitoring</h3><div className="space-y-2">{newRbt.slice(0, 5).map((r) => <div key={r.id} className="rounded-xl border border-border/60 bg-background p-3"><p className="font-medium text-foreground">{r.rbt} · {r.client}</p><p className="text-xs text-muted-foreground">First 1–2 week check-in: {r.tasks.length ? "Due" : "Complete"}</p><p className="text-xs text-muted-foreground">Daily check-ins {r.notesReviewed > 15 ? "on track" : "needs review"} · Early note issues {r.notesFlagged}</p></div>)}</div></div></div></Panel>; }

function OwnerPerformance({ records }: { records: QARecord[] }) { const owners = Array.from(new Set(records.map((r) => r.qaOwner))); return <Panel title="QA Owner Performance" icon={Users}><div className="overflow-x-auto"><table className="w-full text-sm"><thead className="bg-muted/40 text-[11px] uppercase tracking-wider text-muted-foreground"><tr>{["QA Owner", "Assigned", "Completed", "Avg Turnaround", "Issues", "Overdue", "Fix Tasks", "Ready for Auth"].map((h) => <th key={h} className="px-3 py-2 text-left font-medium">{h}</th>)}</tr></thead><tbody>{owners.map((owner) => { const rows = records.filter((r) => r.qaOwner === owner); return <tr key={owner} className="border-t border-border/50"><td className="px-3 py-3 font-medium text-foreground">{owner}</td><td className="px-3 py-3">{rows.length}</td><td className="px-3 py-3">{rows.filter((r) => r.qaCompleted || r.authReadiness === "Ready").length}</td><td className="px-3 py-3">{Math.round(rows.reduce((s, r) => s + r.daysInQA, 0) / Math.max(1, rows.length))}d</td><td className="px-3 py-3">{rows.filter((r) => r.issueType !== "None").length}</td><td className="px-3 py-3">{rows.filter((r) => r.qaStatus === "Overdue").length}</td><td className="px-3 py-3">{rows.reduce((s, r) => s + r.tasks.filter((t) => t.status === "Open").length, 0)}</td><td className="px-3 py-3">{rows.filter((r) => r.authReadiness === "Ready").length}</td></tr>; })}</tbody></table></div></Panel>; }

function Worklist({ records, onSelect, onReady, onCreateFixTask, updateRecord }: { records: QARecord[]; onSelect: (r: QARecord) => void; onReady: (r: QARecord) => void; onCreateFixTask: (r: QARecord) => void; updateRecord: (id: string, patch: Partial<QARecord>, message: string) => void }) { return <Panel title="QA Worklist" icon={ClipboardCheck} action={<span className="text-xs text-muted-foreground">{records.length} records</span>}><div className="overflow-x-auto"><table className="w-full text-sm"><thead className="bg-muted/40 text-[11px] uppercase tracking-wider text-muted-foreground"><tr>{["Client", "State", "BCBA", "QA Owner", "QA Status", "Plan Status", "Days Since Assessment", "Days in QA", "Issue Type", "Auth Readiness", "Next Action", "Alerts"].map((h) => <th key={h} className="whitespace-nowrap px-3 py-2 text-left font-medium">{h}</th>)}</tr></thead><tbody>{records.map((r) => <tr key={r.id} onClick={() => onSelect(r)} className="cursor-pointer border-t border-border/50 hover:bg-muted/25"><td className="px-3 py-3 font-medium text-foreground">{r.client}</td><td className="px-3 py-3">{r.state}</td><td className="px-3 py-3 text-xs text-muted-foreground">{r.bcba}</td><td className="px-3 py-3 text-xs text-muted-foreground">{r.qaOwner}</td><td className="px-3 py-3"><StatusBadge status={r.qaStatus} variant={statusTone(r.qaStatus)} /></td><td className="px-3 py-3">{r.treatmentPlanStatus}</td><td className="px-3 py-3">{r.daysSinceAssessment}</td><td className="px-3 py-3">{r.daysInQA}</td><td className="px-3 py-3">{r.issueType}</td><td className="px-3 py-3"><StatusBadge status={r.authReadiness} variant={statusTone(r.authReadiness)} /></td><td className="px-3 py-3 min-w-52">{r.nextAction}</td><td className="px-3 py-3"><div className="flex flex-wrap gap-1">{r.alerts.slice(0, 2).map((a) => <StatusBadge key={a} status={a} variant="warning" />)}</div></td></tr>)}</tbody></table></div><div className="mt-3 flex gap-2"><Button variant="outline" onClick={() => records[0] && updateRecord(records[0].id, { qaStatus: "Issues Found" }, "First visible item marked issues found")}>Mark first issue</Button><Button variant="outline" onClick={() => records[0] && onCreateFixTask(records[0])}>Create first fix task</Button><Button onClick={() => records[0] && onReady(records[0])}>Mark first ready</Button></div></Panel>; }

function DetailPanel({ record, onOpenChange, onReady, onCreateFixTask, updateRecord }: { record: QARecord | null; onOpenChange: (open: boolean) => void; onReady: (r: QARecord) => void; onCreateFixTask: (r: QARecord) => void; updateRecord: (id: string, patch: Partial<QARecord>, message: string) => void }) {
  const [draftComment, setDraftComment] = useState("");
  const [manualTask, setManualTask] = useState({ title: "", owner: "", due: "" });
  if (!record) return null;
  const checklistRows = [["docs", "Required documents present"], ["plan", "Treatment plan complete"], ["clinical", "Clinical accuracy checked"], ["formatting", "Formatting complete"], ["signature", "Parent signature if needed"], ["ready", "Ready for submission"]] as const;
  const setCheck = (key: string, checked: boolean, message: string) => updateRecord(record.id, { checklist: { ...record.checklist, [key]: checked } }, message);
  const addComment = () => { if (!draftComment.trim()) return; updateRecord(record.id, { comments: [...record.comments, draftComment.trim()] }, "QA comment added"); setDraftComment(""); };
  const addManualTask = () => { const title = manualTask.title.trim() || `QA follow-up: ${record.issueType === "None" ? "Documentation review" : record.issueType}`; const owner = manualTask.owner.trim() || record.bcba; const due = manualTask.due.trim() || "Tomorrow"; updateRecord(record.id, { tasks: [...record.tasks, { title, owner, due, status: "Open", linkedRecordId: record.id, createdFrom: "QA Detail" }], alerts: Array.from(new Set([...record.alerts, "Fix task open"])), nextAction: `Complete ${title}` }, "Task added to QA record"); setManualTask({ title: "", owner: "", due: "" }); };
  const completeTask = (title: string) => updateRecord(record.id, { tasks: record.tasks.map((task) => task.title === title ? { ...task, status: "Done" as const } : task) }, "Task completed");
  const addTimeline = (label: string, detail: string) => updateRecord(record.id, {}, `${label}: ${detail}`);

  return <Sheet open={!!record} onOpenChange={onOpenChange}><SheetContent className="w-[820px] overflow-y-auto sm:max-w-[820px]"><SheetHeader><SheetTitle>{record.client}</SheetTitle><SheetDescription>{record.state} · {record.bcba} · QA owner {record.qaOwner}</SheetDescription></SheetHeader><div className="mt-5 flex flex-wrap gap-2"><Button onClick={() => onReady(record)}>Mark Ready for Submission</Button><Button variant="outline" onClick={() => updateRecord(record.id, { qaStatus: "Issues Found", authReadiness: "Blocked" }, "Issues found")}>Mark Issues Found</Button><Button variant="outline" onClick={() => onCreateFixTask(record)}>Create Fix Task</Button><Button variant="outline" onClick={() => toast.success(`Notified ${record.bcba}`)}><MessageSquare className="mr-2 h-4 w-4" />Notify BCBA</Button></div><Tabs defaultValue="overview" className="mt-5"><TabsList className="flex h-auto flex-wrap"><TabsTrigger value="overview">Overview</TabsTrigger><TabsTrigger value="plan">Treatment Plan</TabsTrigger><TabsTrigger value="checklist">Checklist</TabsTrigger><TabsTrigger value="issues">Issues</TabsTrigger><TabsTrigger value="notes">Notes Compliance</TabsTrigger><TabsTrigger value="rbt">New RBT Monitoring</TabsTrigger><TabsTrigger value="auth">Auth Connection</TabsTrigger><TabsTrigger value="tasks">Tasks</TabsTrigger><TabsTrigger value="timeline">Timeline</TabsTrigger></TabsList>
    <TabsContent value="overview" className="space-y-3 pt-4"><InfoGrid rows={[["Client", record.client], ["State", record.state], ["BCBA", record.bcba], ["QA owner", record.qaOwner], ["Current QA status", record.qaStatus], ["Days in QA", `${record.daysInQA}`], ["Blockers", record.alerts.join(", ") || "None"]]} /></TabsContent>
    <TabsContent value="plan" className="space-y-4 pt-4"><InfoGrid rows={[["Submitted date", record.planReceived ?? "Missing"], ["Due date", record.planDue], ["Document link", record.documents.join(", ")], ["Version history", "v1 received, v2 if corrections needed"], ["QA comments", record.comments.join(" ") || "No comments yet"]]} /><EditableChecklist rows={[["Treatment plan document uploaded", !!record.planReceived], ["Medical necessity language reviewed", record.checklist.clinical], ["Goals match assessment findings", record.checklist.plan], ["Parent signature attached", record.checklist.signature]]} onToggle={(index, checked) => setCheck(["plan", "clinical", "plan", "signature"][index], checked, "Treatment plan checklist updated")} /><Textarea value={draftComment} onChange={(event) => setDraftComment(event.target.value)} placeholder="Add treatment plan QA comments..." /><div className="flex flex-wrap gap-2"><Button onClick={addComment}>Save Comment</Button><Button variant="outline" onClick={() => updateRecord(record.id, { treatmentPlanStatus: "Corrections sent", qaStatus: "Corrections Needed", authReadiness: "Blocked" }, "Treatment plan corrections requested")}>Request Corrections</Button><Button variant="outline" onClick={() => setCheck("plan", true, "Treatment plan approved")}>Approve Plan</Button></div></TabsContent>
    <TabsContent value="checklist" className="space-y-4 pt-4"><div className="space-y-2">{checklistRows.map(([key, label]) => <label key={key} className="flex items-center gap-3 rounded-xl border border-border/60 bg-background p-3 text-sm text-foreground"><Checkbox checked={record.checklist[key]} onCheckedChange={(checked) => setCheck(key, checked === true, "Checklist updated")} />{label}</label>)}</div><div className="flex flex-wrap gap-2"><Button variant="outline" onClick={() => updateRecord(record.id, { checklist: Object.fromEntries(checklistRows.map(([key]) => [key, true])) as Record<string, boolean> }, "All checklist items completed")}>Complete All</Button><Button onClick={() => onReady(record)}>Mark Ready</Button></div></TabsContent>
    <TabsContent value="issues" className="space-y-4 pt-4"><InfoGrid rows={[["Issue type", record.issueType], ["Description", record.comments[0] ?? record.issueType], ["Assigned fix owner", record.bcba], ["Due date", record.tasks[0]?.due ?? "—"], ["Resolution status", record.issueType === "None" ? "No issues" : "Open"]]} /><EditableChecklist rows={[["Issue documented", record.issueType !== "None"], ["Owner assigned", record.tasks.some((task) => task.status === "Open")], ["Correction due date set", !!record.tasks[0]?.due], ["Auth blocker marked", record.authReadiness === "Blocked"]]} onToggle={(_, checked) => checked && onCreateFixTask(record)} /><div className="flex flex-wrap gap-2"><Button onClick={() => onCreateFixTask(record)}>Create Fix Task</Button><Button variant="outline" onClick={() => updateRecord(record.id, { issueType: "None", qaStatus: "In Review", alerts: record.alerts.filter((alert) => !alert.includes("Issues")) }, "Issue resolved")}>Resolve Issue</Button></div></TabsContent>
    <TabsContent value="notes" className="space-y-4 pt-4"><InfoGrid rows={[["Flagged notes", `${record.notesFlagged}`], ["NoteGuard issues", `${record.noteGuardIssues}`], ["Amerigroup notes", record.amerigroupIssue ? "Issue found" : "Clear"], ["RBT correction tasks", record.tasks.filter((t) => t.title.toLowerCase().includes("note") || t.title.toLowerCase().includes("rbt")).length.toString()]]} /><EditableChecklist rows={[["NoteGuard export reviewed", record.noteGuardIssues === 0], ["Repeated note errors coached", record.repeatNoteErrors === 0], ["Amerigroup note rules checked", !record.amerigroupIssue], ["RBT correction task created", record.tasks.some((task) => task.title.toLowerCase().includes("note") || task.title.toLowerCase().includes("rbt"))]]} onToggle={(_, checked) => checked && updateRecord(record.id, { notesFlagged: Math.max(0, record.notesFlagged - 1), noteGuardIssues: Math.max(0, record.noteGuardIssues - 1) }, "Notes compliance updated")} /><Button variant="outline" onClick={() => onCreateFixTask(record)}>Assign Note Coaching Task</Button></TabsContent>
    <TabsContent value="rbt" className="space-y-4 pt-4"><InfoGrid rows={[["Linked RBT", record.rbt], ["New RBT", record.newRbt ? "Yes" : "No"], ["Check-in schedule", record.newRbt ? "Daily first week, biweekly after" : "Standard monitoring"], ["First week status", record.newRbt ? (record.alerts.some((a) => a.includes("RBT")) ? "Needs check-in" : "On track") : "Not applicable"], ["Early compliance notes", `${record.notesFlagged} flagged notes`]]} /><EditableChecklist rows={[["First-week check-in completed", !record.alerts.some((a) => a.includes("RBT"))], ["Daily notes reviewed", record.notesReviewed > 15], ["Supervisor coaching assigned", record.tasks.some((task) => task.title.toLowerCase().includes("coaching"))], ["Early risk documented", record.newRbt && record.notesFlagged > 0]]} onToggle={(_, checked) => checked && updateRecord(record.id, { alerts: record.alerts.filter((alert) => !alert.includes("RBT")) }, "RBT monitoring checklist updated")} /><Button variant="outline" onClick={() => updateRecord(record.id, { tasks: [...record.tasks, { title: "New RBT supervisor check-in", owner: record.qaOwner, due: "Tomorrow", status: "Open", linkedRecordId: record.id, createdFrom: "QA Detail" }] }, "RBT check-in task created")}>Schedule Check-In</Button></TabsContent>
    <TabsContent value="auth" className="space-y-4 pt-4"><InfoGrid rows={[["Linked treatment auth", `${record.id.replace("QA", "AUTH")}`], ["Auth status", record.authStatus], ["Blocking submission", record.authReadiness === "Ready" ? "Nothing" : record.alerts.join(", ") || record.issueType]]} /><EditableChecklist rows={[["QA status ready", record.qaStatus === "Ready for Submission"], ["Required docs clear", record.checklist.docs], ["No open blockers", record.authReadiness === "Ready"], ["Client stage pending treatment auth", record.stage === "Pending Treatment Auth"]]} onToggle={(_, checked) => checked && updateRecord(record.id, { authReadiness: "Ready", authStatus: "Awaiting Submission" }, "Auth connection updated")} /><Button onClick={() => onReady(record)}>Set QA Ready + Auth Awaiting Submission</Button></TabsContent>
    <TabsContent value="tasks" className="space-y-4 pt-4"><div className="grid gap-2 md:grid-cols-3"><Input value={manualTask.title} onChange={(event) => setManualTask({ ...manualTask, title: event.target.value })} placeholder="Task title" /><Input value={manualTask.owner} onChange={(event) => setManualTask({ ...manualTask, owner: event.target.value })} placeholder="Owner" /><Input value={manualTask.due} onChange={(event) => setManualTask({ ...manualTask, due: event.target.value })} placeholder="Due date" /></div><Button onClick={addManualTask}>Add Linked Task</Button><div className="space-y-2">{[...record.tasks, { title: "Completed checklist review", owner: record.qaOwner, due: "Apr 26", status: "Done" as const }].map((task) => <div key={task.title} className="flex items-center justify-between rounded-xl border border-border/60 bg-background p-3"><div><p className="font-medium text-foreground">{task.title}</p><p className="text-xs text-muted-foreground">{task.owner} · {task.due}{task.linkedRecordId ? ` · ${task.linkedRecordId}` : ""}</p></div><div className="flex items-center gap-2"><StatusBadge status={task.status} variant={task.status === "Done" ? "success" : "warning"} />{task.status === "Open" && <Button size="sm" variant="outline" onClick={() => completeTask(task.title)}>Complete</Button>}</div></div>)}</div></TabsContent>
    <TabsContent value="timeline" className="space-y-4 pt-4"><div className="flex flex-wrap gap-2"><Button variant="outline" onClick={() => addTimeline("Manual QA update", "Progress note added from timeline tab")}>Add Update</Button><Button variant="outline" onClick={() => addTimeline("BCBA notified", `${record.bcba} notified from timeline tab`)}>Log BCBA Notice</Button></div><div className="space-y-3">{record.timeline.map((event) => <div key={`${event.label}-${event.date}`} className="border-l border-border/60 pl-4"><p className="font-medium text-foreground">{event.label}</p><p className="text-xs text-muted-foreground">{event.date} · {event.detail}</p></div>)}</div></TabsContent>
  </Tabs></SheetContent></Sheet>;
}

function EditableChecklist({ rows, onToggle }: { rows: [string, boolean][]; onToggle: (index: number, checked: boolean) => void }) {
  return <div className="grid gap-2 md:grid-cols-2">{rows.map(([label, checked], index) => <label key={label} className="flex items-center gap-3 rounded-xl border border-border/60 bg-background p-3 text-sm text-foreground"><Checkbox checked={checked} onCheckedChange={(value) => onToggle(index, value === true)} />{label}</label>)}</div>;
}

function InfoGrid({ rows }: { rows: [string, string][] }) { return <div className="grid gap-3 md:grid-cols-2">{rows.map(([label, value]) => <div key={label} className="rounded-xl border border-border/60 bg-background p-3"><p className="text-xs text-muted-foreground">{label}</p><p className="mt-1 text-sm font-medium text-foreground">{value || "—"}</p></div>)}</div>; }
